import { getCoreContextInitScript } from '@nordic/core-context/server';

import { getContext } from '../storage';
import {
  getRenderingContextInitScript,
  getNativeActionInitScripts,
  getPipeableStreamInitScript,
} from './getters';

export function getRenderingContextInitScripts() {
  const { flags } = getContext();

  return [
    getCoreContextInitScript(flags.staticMarkup),
    getRenderingContextInitScript(),
    getNativeActionInitScripts(),
    getPipeableStreamInitScript(),
  ];
}
